'math_6_T15': [
  { type:'mcq', q:'To find the absolute maximum of \\(f(x) = x^3 - 3x + 2\\) on \\([-2, 2]\\), we evaluate \\(f\\) at:', options:['A. Only critical points', 'B. Only endpoints', 'C. Critical points and endpoints', 'D. Only the midpoint'], answer:2, explain:'To find the absolute extrema on a closed interval \\([a,b]\\), evaluate \\(f\\) at all critical points in \\((a,b)\\) and at the endpoints \\(a, b\\).', _section:'mcq', _source:'ISC-pattern', id:'mcq_math6_T15_1' },
  { type:'mcq', q:'The absolute maximum of \\(f(x) = x^3 - 3x + 2\\) on \\([-2, 2]\\) is:', options:['A. 2', 'B. 4', 'C. 0', 'D. -4'], answer:1, explain:'Critical points: \\(f\'=3x^2-3=0\\Rightarrow x=\\pm 1\\); \\(f(-2)=0\\), \\(f(-1)=4\\), \\(f(1)=0\\), \\(f(2)=4\\); absolute max is 4.', _section:'mcq', _source:'ISC-pattern', id:'mcq_math6_T15_2' },
  { type:'mcq', q:'The absolute minimum of \\(f(x) = x^2 - 4x + 5\\) on \\([0, 3]\\) is:', options:['A. 0', 'B. 1', 'C. 2', 'D. 5'], answer:1, explain:'\\(f\'=2x-4=0\\Rightarrow x=2\\in[0,3]\\); \\(f(0)=5\\), \\(f(2)=1\\), \\(f(3)=2\\); absolute min is \\(f(2)=1\\).', _section:'mcq', _source:'ISC-pattern', id:'mcq_math6_T15_3' },
],

