'math_6_T17': [
  { type:'mcq', q:'A wire of length 36 cm is bent to form a rectangle. To maximise area, the dimensions should be:', options:['A. 12 cm × 6 cm', 'B. 9 cm × 9 cm', 'C. 18 cm × 9 cm', 'D. 15 cm × 3 cm'], answer:1, explain:'For fixed perimeter, area is maximised when the shape is a square; \\(2(l+b)=36 \\Rightarrow l+b=18\\); square: \\(9 \\times 9\\).', _section:'mcq', _source:'ISC-pattern', id:'mcq_math6_T17_1' },
  { type:'mcq', q:'A box with a square base and open top is to have volume 32 cm\\(^3\\). To minimise surface area, the side of the base should be:', options:['A. 2 cm', 'B. 4 cm', 'C. 8 cm', 'D. 16 cm'], answer:1, explain:'\\(V=a^2h=32\\Rightarrow h=32/a^2\\); \\(S=a^2+4ah=a^2+128/a\\); \\(\\frac{dS}{da}=2a-128/a^2=0\\Rightarrow a^3=64\\Rightarrow a=4\\).', _section:'mcq', _source:'ISC-pattern', id:'mcq_math6_T17_2' },
  { type:'mcq', q:'The sum of two numbers is 24. Their product is maximum when each number is:', options:['A. 6 and 18', 'B. 12 and 12', 'C. 8 and 16', 'D. 10 and 14'], answer:1, explain:'If \\(x+(24-x)=24\\), product \\(P=x(24-x)=-x^2+24x\\) is maximum at \\(x=12\\) (AM-GM or calculus).', _section:'mcq', _source:'ISC-pattern', id:'mcq_math6_T17_3' },
],

